/// Convert a borrowed FPSS event into its typed `#[pyclass]` in a
/// single pass. Owned strings / byte buffers are materialised
/// exactly once; the contract is stored inline so the nested
/// `ContractRef` Python object is built only on `event.contract`
/// access.
pub(crate) fn fpss_event_to_typed(
    py: Python<'_>,
    event: &fpss::StreamEvent,
) -> PyResult<Py<PyAny>> {
    match event {
        fpss::StreamEvent::Data(data) => match data {
            fpss::StreamData::MarketValue {
                contract,
                ms_of_day,
                market_bid,
                market_ask,
                market_price,
                date,
                received_at_ns,
                ..
            } => Py::new(
                py,
                MarketValue {
                    contract: (**contract).clone(),
                    ms_of_day: *ms_of_day,
                    market_bid: *market_bid,
                    market_ask: *market_ask,
                    market_price: *market_price,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamData::Ohlcvc {
                contract,
                ms_of_day,
                open,
                high,
                low,
                close,
                volume,
                count,
                date,
                received_at_ns,
                ..
            } => Py::new(
                py,
                Ohlcvc {
                    contract: (**contract).clone(),
                    ms_of_day: *ms_of_day,
                    open: *open,
                    high: *high,
                    low: *low,
                    close: *close,
                    volume: *volume,
                    count: *count,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamData::OpenInterest {
                contract,
                ms_of_day,
                open_interest,
                date,
                received_at_ns,
                ..
            } => Py::new(
                py,
                OpenInterest {
                    contract: (**contract).clone(),
                    ms_of_day: *ms_of_day,
                    open_interest: *open_interest,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamData::Quote {
                contract,
                ms_of_day,
                bid_size,
                bid_exchange,
                bid,
                bid_condition,
                ask_size,
                ask_exchange,
                ask,
                ask_condition,
                date,
                received_at_ns,
                ..
            } => Py::new(
                py,
                Quote {
                    contract: (**contract).clone(),
                    ms_of_day: *ms_of_day,
                    bid_size: *bid_size,
                    bid_exchange: *bid_exchange,
                    bid: *bid,
                    bid_condition: *bid_condition,
                    ask_size: *ask_size,
                    ask_exchange: *ask_exchange,
                    ask: *ask,
                    ask_condition: *ask_condition,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamData::Trade {
                contract,
                ms_of_day,
                sequence,
                condition,
                size,
                exchange,
                price,
                date,
                received_at_ns,
                ..
            } => Py::new(
                py,
                Trade {
                    contract: (**contract).clone(),
                    ms_of_day: *ms_of_day,
                    sequence: *sequence,
                    condition: *condition,
                    size: *size,
                    exchange: *exchange,
                    price: *price,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any()),
            _ => Py::new(py, UnknownControl).map(|p| p.into_any()),
        },
        fpss::StreamEvent::Control(ctrl) => match ctrl {
            fpss::StreamControl::Connected => Py::new(py, Connected).map(|p| p.into_any()),
            fpss::StreamControl::ContractAssigned { id, contract } => Py::new(
                py,
                ContractAssigned {
                    id: *id,
                    contract: (**contract).clone(),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::Disconnected { reason } => Py::new(
                py,
                Disconnected {
                    reason: i32::from(*reason as i16),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::LoginSuccess { permissions } => Py::new(
                py,
                LoginSuccess {
                    permissions: permissions.clone(),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::MarketClose => Py::new(py, MarketClose).map(|p| p.into_any()),
            fpss::StreamControl::MarketOpen => Py::new(py, MarketOpen).map(|p| p.into_any()),
            fpss::StreamControl::Error { message } => Py::new(
                py,
                ParseError {
                    message: message.clone(),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::Ping { payload } => Py::new(
                py,
                Ping {
                    payload: payload.clone(),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::Reconnected => Py::new(py, Reconnected).map(|p| p.into_any()),
            fpss::StreamControl::ReconnectedServer => Py::new(py, ReconnectedServer).map(|p| p.into_any()),
            fpss::StreamControl::Reconnecting { reason, attempt, delay_ms } => Py::new(
                py,
                Reconnecting {
                    reason: i32::from(*reason as i16),
                    attempt: i32::try_from(*attempt).unwrap_or(i32::MAX),
                    delay_ms: *delay_ms,
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::ReconnectsExhausted { reason, attempts } => Py::new(
                py,
                ReconnectsExhausted {
                    reason: i32::from(*reason as i16),
                    attempts: i32::try_from(*attempts).unwrap_or(i32::MAX),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::ReqResponse { req_id, result } => Py::new(
                py,
                ReqResponse {
                    req_id: *req_id,
                    result: i32::from(*result as u8),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::Restart => Py::new(py, Restart).map(|p| p.into_any()),
            fpss::StreamControl::ServerError { message } => Py::new(
                py,
                ServerError {
                    message: message.clone(),
                },
            )
            .map(|p| p.into_any()),
            fpss::StreamControl::UnknownFrame { code, payload } => Py::new(
                py,
                UnknownFrame {
                    code: *code,
                    payload: payload.clone(),
                },
            )
            .map(|p| p.into_any()),
            _ => Py::new(py, UnknownControl).map(|p| p.into_any()),
        },
        _ => Py::new(py, UnknownControl).map(|p| p.into_any()),
    }
}

pub(crate) fn register_fpss_event_classes(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add_class::<ContractRef>()?;
    m.add_class::<Connected>()?;
    m.add_class::<ContractAssigned>()?;
    m.add_class::<Disconnected>()?;
    m.add_class::<LoginSuccess>()?;
    m.add_class::<MarketClose>()?;
    m.add_class::<MarketOpen>()?;
    m.add_class::<MarketValue>()?;
    m.add_class::<Ohlcvc>()?;
    m.add_class::<OpenInterest>()?;
    m.add_class::<ParseError>()?;
    m.add_class::<Ping>()?;
    m.add_class::<Quote>()?;
    m.add_class::<Reconnected>()?;
    m.add_class::<ReconnectedServer>()?;
    m.add_class::<Reconnecting>()?;
    m.add_class::<ReconnectsExhausted>()?;
    m.add_class::<ReqResponse>()?;
    m.add_class::<Restart>()?;
    m.add_class::<ServerError>()?;
    m.add_class::<Trade>()?;
    m.add_class::<UnknownControl>()?;
    m.add_class::<UnknownFrame>()?;
    Ok(())
}
